import{_ as o,o as t,c as a,a3 as n}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"45. Shiftwork","description":"","frontmatter":{"title":"45. Shiftwork","eba":"Health Allied & Managers Admin 2021-2025","topics":["hours","shift-work","allowances","preliminary"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/allowances/45-shiftwork.md","filePath":"ebas/has-managers-admin/common-terms/allowances/45-shiftwork.md"}'),s={name:"ebas/has-managers-admin/common-terms/allowances/45-shiftwork.md"};function r(i,e,h,l,p,m){return t(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="_45-shiftwork" tabindex="-1">45. Shiftwork <a class="header-anchor" href="#_45-shiftwork" aria-label="Permalink to &quot;45. Shiftwork&quot;">​</a></h1><p><strong>45.1</strong> Employees who perform shift work will be entitled to payment of the shift allowances applying to their classification under the following provisions of this clause.</p><p><strong>45.2</strong> Morning and Afternoon Shift Allowances</p><p><strong>(a)</strong> An Employee not employed by Royal Women’s Hospital or Royal Children’s Hospital whose rostered hours of ordinary duty:</p><p><strong>(i)</strong> commence between 5:00am and 6:30am, or</p><p><strong>(ii)</strong> finish between 6:00pm and before midnight will be paid the applicable shift allowance set out in Part 1 or Part 2 of <a href="/eba/ebas/has-managers-admin/schedules/2c-allowances-health-allied-services.html">Schedule 2C</a> or Part 1 of <a href="/eba/ebas/has-managers-admin/schedules/3c-allowances-managers-and-administrative-workers.html">Schedule 3C</a> (as applicable) per rostered period of duty, unless the Employee is entitled to Night Shift Allowance or Permanent Night Shift Allowance.</p><p><strong>(b)</strong> An Employee employed by Royal Women’s Hospital or Royal Children’s Hospital whose rostered hours of ordinary duty</p><p><strong>(i)</strong> commence between 5:00am and 6:30am, or</p><p><strong>(ii)</strong> finish between 8:00pm and before midnight will be paid the applicable shift allowance set out in Part 2 of Allowance or Permanent Night Shift Allowance.</p><p><strong>45.3</strong> Night Shift Allowance</p><p><strong>(a)</strong> An Employee whose rostered hours of ordinary duty:</p><p><strong>(i)</strong> commence after midnight and before 5.00am, or</p><p><strong>(ii)</strong> finish on the day after commencing duty will be paid the applicable Night Shift Allowance set out in Part 1 or Part 2 of <a href="/eba/ebas/has-managers-admin/schedules/2c-allowances-health-allied-services.html">Schedule 2C</a> or Part 1 or Part 2 of <a href="/eba/ebas/has-managers-admin/schedules/3c-allowances-managers-and-administrative-workers.html">Schedule 3C</a> (as applicable) for each such period of duty, unless the Employee is entitled to Permanent Night Shift Allowance.</p><p><strong>45.4</strong> Permanent Night Shift Allowance</p><p><strong>(a)</strong> An Employee who permanently works rostered hours of ordinary duty:</p><p><strong>(i)</strong> commence after midnight and before 5.00am, or</p><p><strong>(ii)</strong> that finish on the day after commencing duty will be paid the applicable Permanent Night Shift allowance set out in Part 1 or Part 2 of <a href="/eba/ebas/has-managers-admin/schedules/2c-allowances-health-allied-services.html">Schedule 2C</a> or Part 1 or Part 2 of</p><p><strong>(b)</strong> Permanently works means that all rostered hours of ordinary duty performed by the Employee attracted the Night Shift Allowance for more than four consecutive weeks.</p><p><strong>45.5</strong> Change of Shift Allowance</p><p><strong>(a)</strong> The change of shift allowance set out in Part 1 or Part 2 of payable to Employees on the occasion of each change in the following circumstances (in addition to any amount payable under the preceding provisions of this clause):</p><p><strong>(i)</strong> where an Employee’s roster is fixed in advance by the Employer; and</p><p><strong>(ii)</strong> the Employee changes from working on one shift to working on another shift the time of commencement of which differs by four hours or more from that of the first.</p><p><strong>(b)</strong> Exceptions The change of shift allowance is not payable where:</p><p><strong>(i)</strong> the Employer agrees to a request in writing made on behalf of one or more Employees for changes in shifts; or</p><p><strong>(ii)</strong> a single Employee holds two contemporaneous different contracted positions with the same employer and moving between those positions results in a change of shift pattern which would ordinarily invoke a change of shift allowance payment;</p><p><strong>(iii)</strong> an Employee chooses and works additional shifts from a supplementary roster, that displays vacant shifts and Employees can nominate to work those shifts. The supplementary roster would also provide a stand-by facility, where Employees wishing to work extra shifts can nominate the days/shifts that they wish to work, should such vacancies in the normal roster occur;</p><p><strong>(iv)</strong> the absence of four or more weeks of continuous approved leave intervenes between the relevant shifts;</p><p><strong>(v)</strong> one or more Employees swap shifts between themselves on an ad hoc basis, and the swap(s) is approved by the Employer in writing. Health &amp; Allied Services and Dental Assistants only</p><p><strong>(c)</strong> Where a department has established a self-rostering system, and an Employee chooses their own shifts from a genuine choice of shifts, the Employee will receive a fixed payment of two change of shift allowances per pay period (fortnight) and subclause 45.5(a) will not apply. This clause does not apply where an Employee chooses their own shifts from a genuine choice of shifts and the shifts chosen by the Employee do not involve a change of shift as defined by subclause 45.5(a).</p><p><strong>(d)</strong> An Employee employed in the public sector as of 11 June 2002, who receives change of shift allowances per pay period (fortnight) on the basis of an historical agreement that exceeds the entitlement arising from these provisions, such Employee will be maintained at that entitlement for the duration of this agreement.</p><p><strong>(e)</strong> Where an Employer and the majority of Employees in a department genuinely desire an alternative system to the above, the Employer is to contact the HWU and any agreement reached will be determined in accordance with the facilitative provisions of this Agreement.</p><p>PART F – HOURS OF WORK AND RELATED MATTERS</p><p>Plain language terms: shift penalty, shift loading, afternoon shift, night shift pay.</p>',33)])])}const d=o(s,[["render",r]]);export{f as __pageData,d as default};
